import { supabase } from '@/lib/supabase'

export interface DailyDeckStats {
  date: string // ISO format: YYYY-MM-DD
  deck: string
  count: number
  user?: string
}

export interface FlashManStats {
  dailyDeckStats: DailyDeckStats[]
}

export async function getFlashManStats(
  fromDate: string,
  toDate: string,
  userId?: string,
  allUsers?: boolean
): Promise<FlashManStats> {
  const {
    data: { session },
  } = await supabase.auth.getSession()

  const { data, error } = await supabase.functions.invoke<FlashManStats>('query-flashman-stats', {
    body: {
      fromDate,
      toDate,
      userId: allUsers ? undefined : userId || session?.user?.user_metadata?.user_name,
      allUsers,
    },
    headers: {
      Authorization: `Bearer ${session?.access_token}`,
    },
  })

  if (error) {
    // eslint-disable-next-line no-console
    console.error('Function invoke error:', error)
    throw new Error(`Failed to fetch flashman stats: ${error.message}`)
  }

  if (!data) {
    throw new Error('No data returned from flashman stats')
  }

  return data
}
