import { useMemo } from 'react'

import { useQuery } from '@tanstack/react-query'
import dayjs from 'dayjs'
import { useSearchParams } from 'react-router-dom'

import {
  Container,
  Typography,
  Box,
  Paper,
  CircularProgress,
  Alert,
  Stack,
  Chip,
  TextField,
  FormControlLabel,
  Checkbox,
} from '@mui/material'
import { AdapterDayjs } from '@mui/x-date-pickers/AdapterDayjs'
import { DatePicker } from '@mui/x-date-pickers/DatePicker'
import { LocalizationProvider } from '@mui/x-date-pickers/LocalizationProvider'

import { type DailyDeckStats, getFlashManStats } from '@/api/flashManStats'

interface DailyGroup {
  date: string
  decks: Array<{ deck: string; count: number; user?: string }>
  totalCount: number
}

export function FlashManStatsPage() {
  const [searchParams, setSearchParams] = useSearchParams()

  const fromDate = dayjs(
    searchParams.get('fromDate') ?? dayjs().subtract(7, 'day').format('YYYY-MM-DD')
  )
  const toDate = dayjs(searchParams.get('toDate') ?? dayjs().format('YYYY-MM-DD'))
  const userId = searchParams.get('userId') ?? ''
  const allUsers = searchParams.get('allUsers') === 'true'

  const {
    data: stats,
    isLoading,
    error,
  } = useQuery({
    queryKey: [
      'flashman-stats',
      fromDate.format('YYYY-MM-DD'),
      toDate.format('YYYY-MM-DD'),
      userId,
      allUsers,
    ],
    queryFn: () =>
      getFlashManStats(
        fromDate.format('YYYY-MM-DD'),
        toDate.format('YYYY-MM-DD'),
        userId || undefined,
        allUsers
      ),
  })

  const dailyGroups = useMemo(() => {
    if (!stats) return []

    const groupMap = new Map<string, DailyDeckStats[]>()
    stats.dailyDeckStats.forEach((item) => {
      const existing = groupMap.get(item.date) || []
      existing.push(item)
      groupMap.set(item.date, existing)
    })

    const groups: DailyGroup[] = []
    groupMap.forEach((decks, date) => {
      groups.push({
        date,
        decks: decks.map((d) => ({ deck: d.deck, count: d.count, user: d.user })),
        totalCount: decks.reduce((sum, d) => sum + d.count, 0),
      })
    })

    groups.sort((a, b) => b.date.localeCompare(a.date))
    return groups
  }, [stats])

  const getDeckShortName = (deckPath: string) => {
    const parts = deckPath.split('/')
    return parts[parts.length - 1] || deckPath
  }

  const formatDate = (dateStr: string) => {
    const date = new Date(dateStr)
    const weekdays = ['일', '월', '화', '수', '목', '금', '토']
    const month = date.getMonth() + 1
    const day = date.getDate()
    const weekday = weekdays[date.getDay()]
    return `${month}/${day} (${weekday})`
  }

  return (
    <LocalizationProvider dateAdapter={AdapterDayjs}>
      <Container maxWidth="md">
        <Box sx={{ my: 4 }}>
          <Typography variant="h4" component="h1" gutterBottom>
            FlashMan 통계
          </Typography>
          <Box sx={{ display: 'flex', gap: 2, alignItems: 'center', mb: 3, flexWrap: 'wrap' }}>
            <TextField
              label="User ID"
              size="small"
              value={userId}
              onChange={(e) =>
                setSearchParams((p) => ({ ...Object.fromEntries(p), userId: e.target.value }))
              }
              placeholder="GitHub username"
              disabled={allUsers}
              sx={{ minWidth: 160 }}
            />
            <FormControlLabel
              control={
                <Checkbox
                  checked={allUsers}
                  onChange={(e) =>
                    setSearchParams((p) => ({
                      ...Object.fromEntries(p),
                      allUsers: String(e.target.checked),
                    }))
                  }
                />
              }
              label="전체 사용자"
            />
            <DatePicker
              label="시작일"
              value={fromDate}
              onChange={(v) =>
                v &&
                setSearchParams((p) => ({
                  ...Object.fromEntries(p),
                  fromDate: v.format('YYYY-MM-DD'),
                }))
              }
              maxDate={toDate}
              slotProps={{ textField: { size: 'small' } }}
            />
            <DatePicker
              label="종료일"
              value={toDate}
              onChange={(v) =>
                v &&
                setSearchParams((p) => ({
                  ...Object.fromEntries(p),
                  toDate: v.format('YYYY-MM-DD'),
                }))
              }
              minDate={fromDate}
              maxDate={dayjs()}
              slotProps={{ textField: { size: 'small' } }}
            />
          </Box>

          {isLoading && (
            <Box sx={{ display: 'flex', justifyContent: 'center', py: 8 }}>
              <CircularProgress />
            </Box>
          )}

          {error && (
            <Alert severity="error" sx={{ mb: 2 }}>
              {error instanceof Error ? error.message : '데이터를 불러오는데 실패했습니다.'}
            </Alert>
          )}

          {!isLoading && stats && (
            <Stack spacing={2}>
              {dailyGroups.length === 0 ? (
                <Alert severity="info">학습 기록이 없습니다.</Alert>
              ) : (
                dailyGroups.map((group) => (
                  <Paper key={group.date} sx={{ p: 2 }}>
                    <Box
                      sx={{
                        display: 'flex',
                        justifyContent: 'space-between',
                        alignItems: 'center',
                        mb: 1,
                      }}
                    >
                      <Typography variant="subtitle1" fontWeight="bold">
                        {formatDate(group.date)}
                      </Typography>
                      <Typography variant="body2" color="text.secondary">
                        총 {group.totalCount.toLocaleString()}장
                      </Typography>
                    </Box>
                    <Box sx={{ display: 'flex', flexWrap: 'wrap', gap: 1 }}>
                      {group.decks.map((deck) => (
                        <Chip
                          key={`${deck.user ?? ''}:${deck.deck}`}
                          label={
                            allUsers && deck.user
                              ? `${deck.user} · ${getDeckShortName(deck.deck)}: ${deck.count}`
                              : `${getDeckShortName(deck.deck)}: ${deck.count}`
                          }
                          size="small"
                          variant="outlined"
                        />
                      ))}
                    </Box>
                  </Paper>
                ))
              )}
            </Stack>
          )}
        </Box>
      </Container>
    </LocalizationProvider>
  )
}
